#!/usr/bin/env bash
# 0-1.sh — 起号 0→1（垂直度/养号/前几条/破播放） SOP walkthrough for 小红书 AI 自媒体博主.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="小红书 AI 自媒体博主"
WORKFLOW="起号 0→1（垂直度/养号/前几条/破播放）"

usage() {
  cat <<EOF
0-1.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./0-1.sh             # interactive
  ./0-1.sh --dry-run
  ./0-1.sh --json
  ./0-1.sh --explain
  ./0-1.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "起号 0→1（垂直度/养号/前几条/破播放）" 工作流。

一句话: 新账号冷启动到稳定破播放、垂直度达标、开始变现的全流程。

入门 SOP 共 5 步, 失败模式自检 2 项。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**定位**(回答三问：能持续输出什么/目标用户是谁/3 个月怎么变现) (evidence: [T03-S001])"
  "**养号**(争议步骤，见资深差异)：3-7 天像正常用户浏览/点赞/评论/关注 (evidence: [T03-S005])"
  "**前 3 篇测方向**：不同选题/风格各发，看哪类数据好 (evidence: [T03-S005, T03-S006])"
  "**冲量阶段**：第 1 月发 20-30 篇测定位(0→1000 粉)；1-3 月稳更 3-5 篇/周(→5000 粉)；3-6 月爆款频出开始变现 (evidence: [T03-S001])"
  "**破播放**：发后 1-3h 内必回评论(评论推荐权重高)；可找 ~10 人点赞收藏垫基础数据；起势可投薯条 (evidence: [T03-S005, T04-S001(A3)])"
)
declare -a FAILURE_MODES=(
  "批量同一流量密码反复发 → 起量但账号无差异化价值，难持续、易被治理。避免：前 3 篇测方向后聚焦差异化人设。(evidence: [T01-S001])"
  "频繁改账号定位 → 掉权重。避免：定位想清再发。(evidence: [T03-S005])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "0-1-walkthrough"
fi
